MAP
  NAME "TrafficScotland"
  STATUS ON
  EXTENT -180 -90 180 90
  SHAPEPATH "../../layers"

  OUTPUTFORMAT
    NAME "geojson"
    DRIVER "OGR/GEOJSON"
    MIMETYPE "application/json; subtype=geojson"
    FORMATOPTION "STORAGE=stream"
    FORMATOPTION "FORM=SIMPLE"
  END

  LAYER
    NAME "scotland_traffic_network"
    METADATA
      "wfs_title"         "scotland_traffic_network" ##REQUIRED
      "wfs_srs"           "EPSG:4326" ## REQUIRED
      "gml_include_items" "roadname,operator" ## Optional (serves all attributes for layer)
      "gml_featureid"     "fid" ## REQUIRED
      "wfs_enable_request" "* !GetCapabilities"  # necessary
      "wfs_getfeature_formatlist" "geojson"
    END
    TYPE POLYGON
    STATUS ON
    CONNECTIONTYPE OGR
    CONNECTION 'trafficscotland/scotland_traffic_network.gpkg'
    DATA 'scotland_traffic_network'
    PROJECTION
      "init=epsg:4326"
    END
  END #layer

END # End of MAP
